function localizeHtml(html) {
  if (langKey() !== 'en' || !html) return html;
  return Object.entries(zhToEn).sort((a, b) => b[0].length - a[0].length).reduce((out, [zh, en]) => out.split(zh).join(en), html);
}

function loadPrefs() {
  try {
    return { theme: 'system', language: 'zh', ...(JSON.parse(localStorage.getItem('fs_profile_prefs') || '{}')) };
  } catch {
    return { theme: 'system', language: 'zh' };
  }
}

function savePrefs(next) {
  appPrefs = { ...appPrefs, ...next };
  localStorage.setItem('fs_profile_prefs', JSON.stringify(appPrefs));
  applyPreferences();
}

function effectiveTheme() {
  if (appPrefs.theme === 'dark' || appPrefs.theme === 'light') return appPrefs.theme;
  return window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';
}

function applyPreferences() {
  document.body.dataset.theme = effectiveTheme();
  document.documentElement.lang = appPrefs.language === 'en' ? 'en' : 'zh-CN';
  document.title = tr('appTitle', '家庭德育积分系统');
}

function renderRealtimeClock() {
  return `<button type="button" class="realtime-clock" data-clock-toggle data-clock-mode="${globalClockMode}" aria-label="${h(tr('clockNow','当前时间'))}">
    <div class="clock-digital" data-clock-panel="digital"><span>${h(tr('clockNow','当前时间'))}</span><strong data-clock-digital>--</strong><small>${h(tr('clockToggleHint','点击切换表盘'))}</small></div>
    <div class="clock-analog-panel" data-clock-panel="analog"><div class="clock-date"><span>${h(tr('clockDate','日期'))}</span><strong data-clock-date>--</strong><small>${h(tr('clockToggleHintBack','点击切回数字'))}</small></div><div class="analog-clock" aria-hidden="true">
      ${clockTicksHTML()}${clockNumbersHTML()}
      <i class="clock-hand hour" data-clock-hour-hand></i><i class="clock-hand minute" data-clock-minute-hand></i><i class="clock-hand second" data-clock-second-hand></i><i class="clock-pin"></i>
    </div></div>
  </button>`;
}

function mountRealtimeClock() {
  document.querySelectorAll('[data-clock-toggle]').forEach(el => {
    el.dataset.clockMode = globalClockMode;
    el.onclick = () => {
      globalClockMode = globalClockMode === 'digital' ? 'analog' : 'digital';
      document.querySelectorAll('[data-clock-toggle]').forEach(clock => clock.dataset.clockMode = globalClockMode);
      updateGlobalClock();
    };
  });
  updateGlobalClock();
  if (globalClockTimer) return;
  globalClockTimer = setInterval(updateGlobalClock, 1000);
}

function clockTicksHTML() {
  return Array.from({length: 60}, (_, i) => `<i class="clock-tick ${i % 5 === 0 ? 'major' : ''}" style="--tick-angle:${i * 6}deg"></i>`).join('');
}

function clockNumbersHTML() {
  return Array.from({length: 12}, (_, i) => {
    const n = i + 1;
    const angle = (n * 30 - 90) * Math.PI / 180;
    const x = 50 + Math.cos(angle) * 38;
    const y = 50 + Math.sin(angle) * 38;
    return `<span class="clock-number" style="left:${x.toFixed(3)}%;top:${y.toFixed(3)}%">${n}</span>`;
  }).join('');
}

function updateGlobalClock() {
  const now = new Date();
  document.querySelectorAll('[data-clock-digital]').forEach(el => el.textContent = formatClockDateTime(now));
  document.querySelectorAll('[data-clock-date]').forEach(el => el.textContent = formatClockDate(now));
  const secondDeg = now.getSeconds() * 6;
  const minuteDeg = (now.getMinutes() + now.getSeconds() / 60) * 6;
  const hourDeg = ((now.getHours() % 12) + now.getMinutes() / 60 + now.getSeconds() / 3600) * 30;
  document.querySelectorAll('[data-clock-second-hand]').forEach(el => el.style.transform = `translateX(-50%) rotate(${secondDeg}deg)`);
  document.querySelectorAll('[data-clock-minute-hand]').forEach(el => el.style.transform = `translateX(-50%) rotate(${minuteDeg}deg)`);
  document.querySelectorAll('[data-clock-hour-hand]').forEach(el => el.style.transform = `translateX(-50%) rotate(${hourDeg}deg)`);
}

function formatClockDateTime(date) {
  const d = date instanceof Date ? date : new Date(date);
  if (Number.isNaN(d.getTime())) return '-';
  const pad = n => String(n).padStart(2, '0');
  if (langKey() === 'en') return `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())} ${pad(d.getHours())}:${pad(d.getMinutes())}:${pad(d.getSeconds())}`;
  return `${d.getFullYear()}年${pad(d.getMonth() + 1)}月${pad(d.getDate())}日 ${pad(d.getHours())}时${pad(d.getMinutes())}分${pad(d.getSeconds())}秒`;
}

function formatClockDate(date) {
  const d = date instanceof Date ? date : new Date(date);
  if (Number.isNaN(d.getTime())) return '-';
  const pad = n => String(n).padStart(2, '0');
  if (langKey() === 'en') return `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())}`;
  return `${d.getFullYear()}年${pad(d.getMonth() + 1)}月${pad(d.getDate())}日`;
}

async function boot() {
  applyPreferences();
  state.status = await api('/api/system/status');
  if (!state.status.setupCompleted) return renderSetup();
  try {
    const me = await api('/api/auth/me');
    state.me = me.user;
    await loadHome();
  } catch {
    renderLogin();
  }
}

async function loadHome() {
  const children = await api('/api/children');
  state.children = children.children || [];
  if (!state.children.some(c => c.id === state.childId)) state.childId = state.children[0]?.id || null;
  await loadAll();
}

async function loadAll() {
  const result = {};
  const childDashboards = {};
  const reqs = [
    api('/api/profile').then(data => result.profile = data.profile || null),
    api('/api/rewards').then(data => result.rewards = data.rewards || []),
    api('/api/exchange-orders').then(data => result.exchangeOrders = data.exchangeOrders || []),
  ];
  if (canOperate()) {
    reqs.push(api('/api/task-templates').then(data => result.taskTemplates = data.taskTemplates || []));
    reqs.push(api('/api/users').then(data => result.users = data.users || []));
    reqs.push(Promise.allSettled(state.children.map(c => api(`/api/children/${c.id}/dashboard`).then(data => { childDashboards[c.id] = data; }))));
  }
  if (state.childId) {
    reqs.push(api(`/api/children/${state.childId}/dashboard`).then(data => result.dashboard = data));
    reqs.push(api(`/api/children/${state.childId}/score-records`).then(data => result.records = data.records || []));
  }
  await Promise.all(reqs);
  state.rewards = result.rewards || [];
  state.profile = result.profile || null;
  state.exchangeOrders = result.exchangeOrders || [];
  state.taskTemplates = result.taskTemplates || [];
  state.users = result.users || [];
  state.dashboard = result.dashboard || null;
  state.childDashboards = childDashboards;
  if (state.childId && state.dashboard && !state.childDashboards[state.childId]) state.childDashboards[state.childId] = state.dashboard;
  state.records = result.records || [];
  renderApp();
}

:root{
  --bg:#f6f7fb;
  --card:#ffffff;
  --text:#182033;
  --muted:#697386;
  --primary:#4f7cff;
  --primary2:#7c5cff;
  --good:#19a974;
  --warn:#f5a623;
  --bad:#e05260;
  --line:#e7eaf1;
  --hero1:#eef3ff;
  --hero2:#fff7ed;
  --soft:#eef2ff;
  --role-accent:#4f7cff;
}
*{box-sizing:border-box}
body{
  min-height:100vh;
  margin:0;
  font-family:-apple-system,BlinkMacSystemFont,"Segoe UI","PingFang SC","Microsoft YaHei",sans-serif;
  background:linear-gradient(135deg,var(--hero1) 0%,var(--hero2) 100%);
  color:var(--text);
  transition:background .35s ease,color .2s ease;
}
body::before{
  content:"";
  position:fixed;
  inset:0;
  z-index:-1;
  pointer-events:none;
  background:
    radial-gradient(circle at 12% 12%,rgba(255,255,255,.85),transparent 28%),
    radial-gradient(circle at 86% 18%,rgba(255,255,255,.58),transparent 24%),
    radial-gradient(circle at 50% 92%,rgba(255,255,255,.5),transparent 34%);
}
body[data-role="admin"]{--hero1:#e9edff;--hero2:#f5ecff;--soft:#eef2ff;--role-accent:#7c3aed}
body[data-role="parent"]{--hero1:#e8fff4;--hero2:#fff7dc;--soft:#e7fff4;--role-accent:#169b72}
body[data-role="child"]{--hero1:#fff1c7;--hero2:#e6f8ff;--soft:#fff4de;--role-accent:#ff8a3d}
body[data-role="guest"]{--hero1:#eef3ff;--hero2:#fff7ed;--soft:#eef2ff;--role-accent:#4f7cff}
body[data-theme="dark"]{--bg:#0f172a;--card:#172033;--text:#e5edf9;--muted:#9fb0c8;--line:#29364d;--hero1:#101827;--hero2:#1a2438;--soft:#26334d;color-scheme:dark}
body[data-theme="dark"]::before{background:radial-gradient(circle at 12% 12%,rgba(79,124,255,.16),transparent 28%),radial-gradient(circle at 86% 18%,rgba(124,92,255,.14),transparent 24%),radial-gradient(circle at 50% 92%,rgba(25,169,116,.10),transparent 34%)}
body[data-theme="dark"] .card,body[data-theme="dark"] .hero{background:linear-gradient(135deg,rgba(23,32,51,.94),rgba(23,32,51,.72));border-color:rgba(148,163,184,.18)}
body[data-theme="dark"] .tab,body[data-theme="dark"] button.secondary,body[data-theme="dark"] .profile-entry,body[data-theme="dark"] .realtime-clock,body[data-theme="dark"] .field input,body[data-theme="dark"] .field select,body[data-theme="dark"] .field textarea,body[data-theme="dark"] .timeline-item,body[data-theme="dark"] .task-card,body[data-theme="dark"] .reward-card,body[data-theme="dark"] .report-row,body[data-theme="dark"] .speech-card,body[data-theme="dark"] .practice-card,body[data-theme="dark"] .practice-list>div,body[data-theme="dark"] .wishlist-item{background:#172033;color:var(--text);border-color:var(--line)}
body[data-theme="dark"] .analog-clock{background:radial-gradient(circle,#172033 0 55%,#26334d 56% 100%)}body[data-theme="dark"] .clock-pin{box-shadow:0 0 0 3px #172033}
body[data-theme="dark"] .notice{background:#2b230f;color:#ffd98a;border-color:#5b4212}body[data-theme="dark"] .progress-ring-inner{background:#111827}body[data-theme="dark"] .empty-state{background:rgba(23,32,51,.6)}body[data-theme="dark"] .tag{background:#26334d;color:#dbeafe}
button,input,select,textarea{font:inherit}
button{border:0;border-radius:12px;padding:10px 14px;background:linear-gradient(135deg,var(--primary),var(--primary2));color:#fff;cursor:pointer;font-weight:700;box-shadow:0 8px 18px rgba(79,124,255,.18)}
button.secondary{background:#eef2ff;color:#334155;box-shadow:none}
button.danger{background:var(--bad)}
button:disabled{opacity:.55;cursor:not-allowed}
.layout{max-width:1180px;margin:0 auto;padding:24px}
.hero{display:flex;justify-content:space-between;gap:16px;align-items:center;margin-bottom:20px;padding:20px;border:1px solid rgba(255,255,255,.75);border-radius:28px;background:linear-gradient(135deg,rgba(255,255,255,.84),rgba(255,255,255,.58));box-shadow:0 18px 50px rgba(43,55,95,.10);backdrop-filter:blur(14px)}
.hero h1{margin:0 0 6px;font-size:30px}.hero p{margin:0;color:var(--muted)}
.role-note{display:inline-flex;margin-top:10px;padding:7px 12px;border-radius:999px;background:var(--soft);color:var(--role-accent);font-size:13px;font-weight:800}
.grid{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:16px}.grid.two{grid-template-columns:1fr 1fr}
.card{background:rgba(255,255,255,.88);backdrop-filter:blur(12px);border:1px solid rgba(255,255,255,.8);border-radius:22px;padding:18px;box-shadow:0 18px 50px rgba(43,55,95,.10)}
.card h2,.card h3{margin:0 0 14px}.metric{min-height:128px;border-top:4px solid color-mix(in srgb,var(--role-accent) 72%,white)}.metric .label{color:var(--muted);font-size:14px}.metric .value{font-size:36px;font-weight:800;margin-top:8px;color:var(--role-accent)}
.tag{display:inline-flex;align-items:center;border-radius:999px;padding:5px 10px;background:var(--soft);color:#334155;font-size:12px;font-weight:700}.tag.green{background:#e9f9f1;color:#08764f}.tag.blue{background:#edf4ff;color:#2259c7}.tag.yellow{background:#fff7df;color:#9a6500}.tag.orange{background:#fff0e3;color:#b55300}.tag.red{background:#ffe9ec;color:#ad2637}
.row{display:flex;gap:10px;align-items:center;flex-wrap:wrap}.stack{display:flex;flex-direction:column;gap:12px}.form{display:grid;gap:12px}.form.two{grid-template-columns:1fr 1fr}.field{display:grid;gap:6px}.field label{font-size:13px;color:var(--muted);font-weight:700}.field input,.field select,.field textarea{width:100%;border:1px solid var(--line);border-radius:12px;padding:10px 12px;background:#fff;color:var(--text)}.field input:focus,.field select:focus,.field textarea:focus{outline:2px solid color-mix(in srgb,var(--primary) 28%,transparent);border-color:var(--primary)}.field textarea{min-height:82px;resize:vertical}
.table{width:100%;border-collapse:collapse}.table th,.table td{text-align:left;border-bottom:1px solid var(--line);padding:10px 8px;font-size:14px}.table th{color:var(--muted);font-size:12px}.tabs{display:flex;gap:8px;margin:16px 0;flex-wrap:wrap}.tab{background:#fff;color:#334155;box-shadow:none;border:1px solid var(--line)}.tab.active{background:linear-gradient(135deg,var(--primary),var(--primary2));color:#fff;border-color:transparent}.notice{padding:12px 14px;border-radius:14px;background:#fff9e8;color:#7a5200;border:1px solid #ffe1a6}.empty{color:var(--muted);padding:18px;text-align:center}.login{min-height:100vh;display:grid;place-items:center;padding:24px}.login .card{width:min(520px,100%)}.toast{position:fixed;right:20px;bottom:20px;background:#172033;color:#fff;border-radius:14px;padding:12px 16px;box-shadow:0 16px 40px rgba(0,0,0,.2);z-index:10}.split{display:grid;grid-template-columns:1.25fr .75fr;gap:16px}.small{font-size:12px;color:var(--muted)}.captcha-choice{padding:4px;border:2px solid transparent}.captcha-choice.active{border-color:var(--primary);background:#eef2ff}.captcha-choice img{display:block;border-radius:10px}
body[data-role="child"] .metric{border-top-color:#ffb020}body[data-role="child"] .card{border-color:rgba(255,202,102,.55)}body[data-role="parent"] .metric{border-top-color:#22c55e}body[data-role="admin"] .metric{border-top-color:#7c3aed}
@media(max-width:900px){.grid,.grid.two,.split,.form.two{grid-template-columns:1fr}.hero{align-items:flex-start;flex-direction:column}.layout{padding:16px}.table{display:block;overflow-x:auto;white-space:nowrap}}

.eyebrow{color:var(--role-accent);font-size:12px;font-weight:900;letter-spacing:.08em;text-transform:uppercase;margin-bottom:6px}
.hero-panel{display:grid;gap:10px;justify-items:end}
.profile-entry{display:inline-flex;align-items:center;border:1px solid var(--line);border-radius:999px;padding:7px 12px;background:#fff;color:#334155;box-shadow:none;font-size:12px;font-weight:800}
.realtime-clock{display:grid;grid-template-columns:minmax(210px,1fr) auto;gap:12px;align-items:center;justify-self:stretch;min-width:360px;padding:10px;border:1px solid var(--line);border-radius:20px;background:rgba(255,255,255,.64);backdrop-filter:blur(10px)}.clock-digital{display:grid;gap:4px}.clock-digital span,.clock-date span{color:var(--muted);font-size:11px;font-weight:900;letter-spacing:.06em;text-transform:uppercase}.clock-digital strong{font-size:18px;color:var(--role-accent);white-space:nowrap}.clock-analog-panel{display:flex;align-items:center;gap:10px}.clock-date{display:grid;gap:3px;text-align:right}.clock-date strong{font-size:12px;white-space:nowrap}.analog-clock{position:relative;width:74px;height:74px;flex:0 0 auto;border:3px solid var(--role-accent);border-radius:50%;background:radial-gradient(circle,#fff 0 55%,var(--soft) 56% 100%);box-shadow:inset 0 0 0 4px rgba(255,255,255,.55)}.clock-number{position:absolute;color:var(--muted);font-size:10px;font-weight:900}.clock-number.n12{left:50%;top:4px;transform:translateX(-50%)}.clock-number.n3{right:5px;top:50%;transform:translateY(-50%)}.clock-number.n6{left:50%;bottom:3px;transform:translateX(-50%)}.clock-number.n9{left:6px;top:50%;transform:translateY(-50%)}.clock-hand{position:absolute;left:50%;bottom:50%;border-radius:999px;transform-origin:50% 100%;transform:translateX(-50%) rotate(0deg)}.clock-hand.hour{width:4px;height:22px;background:var(--text)}.clock-hand.minute{width:3px;height:28px;background:var(--role-accent)}.clock-hand.second{width:2px;height:31px;background:var(--bad)}.clock-pin{position:absolute;left:50%;top:50%;width:9px;height:9px;border-radius:50%;background:var(--role-accent);transform:translate(-50%,-50%);box-shadow:0 0 0 3px #fff}
.metric{position:relative;overflow:hidden}.metric::after{content:"";position:absolute;right:-28px;top:-28px;width:96px;height:96px;border-radius:50%;background:color-mix(in srgb,var(--role-accent) 12%,transparent)}
.metric-icon{width:38px;height:38px;display:grid;place-items:center;border-radius:15px;background:var(--soft);font-size:22px;margin-bottom:10px}.metric .label,.mini-stat .label{color:var(--muted);font-size:14px}
.section-title{display:flex;justify-content:space-between;align-items:flex-start;gap:12px;margin-bottom:14px}.section-title h2{margin:0 0 4px}.section-title p{margin:0}
.overview-hero-card{display:flex;justify-content:space-between;gap:18px;align-items:center;background:linear-gradient(135deg,rgba(255,255,255,.92),rgba(255,255,255,.64)),radial-gradient(circle at 88% 18%,color-mix(in srgb,var(--role-accent) 20%,transparent),transparent 30%)}
.overview-hero-card h2{margin:0 0 8px;font-size:28px}.overview-hero-card p{margin:0;color:var(--muted)}.overview-actions{display:flex;gap:10px;flex-wrap:wrap;justify-content:flex-end}
.mini-stat-grid{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:16px}.mini-stat{display:flex;gap:12px;align-items:center;min-height:104px}.mini-stat-icon{width:44px;height:44px;flex:0 0 auto;display:grid;place-items:center;border-radius:16px;background:var(--soft);font-size:24px}.mini-stat .value{font-size:28px;font-weight:900;color:var(--role-accent);line-height:1.1}
.task-card-list{display:grid;gap:12px}.task-card{display:flex;align-items:center;justify-content:space-between;gap:14px;padding:14px;border:1px solid var(--line);border-radius:18px;background:linear-gradient(135deg,#fff,rgba(255,255,255,.74))}.task-card.todo{border-color:color-mix(in srgb,var(--primary) 24%,var(--line))}.task-card.pending{border-color:#ffe1a6;background:#fffaf0}.task-card.done{border-color:#bcebd5;background:#f0fff7}.task-card.rejected{border-color:#ffd0d6;background:#fff5f6}
.task-main{display:flex;align-items:center;gap:12px;min-width:0}.task-icon{width:42px;height:42px;display:grid;place-items:center;flex:0 0 auto;border-radius:16px;background:var(--soft);font-size:22px}.task-side{display:flex;align-items:center;gap:10px;flex-wrap:wrap;justify-content:flex-end}
.reward-shelf{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:16px}.reward-shelf.compact{grid-template-columns:repeat(2,minmax(0,1fr))}.reward-card{position:relative;overflow:hidden;display:grid;gap:10px;padding:18px;border:1px solid rgba(255,255,255,.82);border-radius:22px;background:linear-gradient(135deg,rgba(255,255,255,.94),rgba(255,255,255,.72)),radial-gradient(circle at 92% 12%,rgba(255,176,32,.18),transparent 28%);box-shadow:0 14px 36px rgba(43,55,95,.08)}.reward-card h3,.reward-card p{margin:0}.reward-emoji{width:48px;height:48px;display:grid;place-items:center;border-radius:18px;background:#fff7df;font-size:26px}
.score-compass{display:grid;grid-template-columns:140px 1fr;gap:18px;align-items:center}.progress-ring{width:132px;height:132px;border-radius:50%;padding:10px}.progress-ring-inner{width:100%;height:100%;display:grid;place-items:center;align-content:center;border-radius:50%;background:#fff}.progress-ring-inner strong{font-size:34px;line-height:1;color:var(--role-accent)}.progress-ring-inner span{color:var(--muted);font-size:12px;font-weight:800}.progress-line{height:12px;overflow:hidden;border-radius:999px;background:#edf0f7}.progress-line span{display:block;height:100%;border-radius:inherit;background:linear-gradient(135deg,var(--primary),var(--primary2))}
.timeline{position:relative;display:grid;gap:14px}.timeline.compact{gap:10px}.timeline-item{position:relative;display:grid;grid-template-columns:18px 1fr;gap:12px;padding:12px;border:1px solid var(--line);border-radius:18px;background:#fff}.timeline-dot{width:12px;height:12px;margin-top:5px;border-radius:50%;background:var(--role-accent);box-shadow:0 0 0 5px color-mix(in srgb,var(--role-accent) 12%,transparent)}.timeline-item.positive .timeline-dot{background:var(--good)}.timeline-item.warning .timeline-dot{background:var(--warn)}.timeline-item.repair .timeline-dot{background:#7c3aed}.timeline-item.team .timeline-dot{background:#0ea5e9}.timeline-item.star .timeline-dot{background:#f59e0b}.timeline-item.exchange .timeline-dot{background:#ec4899}.timeline-content p,.timeline-item p{margin:6px 0 0;color:var(--muted)}
.empty-state{display:grid;place-items:center;gap:8px;padding:28px 18px;text-align:center;color:var(--muted);border:1px dashed var(--line);border-radius:18px;background:rgba(255,255,255,.58)}.empty-state div{font-size:34px}.empty-state b{color:var(--text)}.empty-state p{margin:0}.table tr:hover td{background:rgba(255,255,255,.58)}
.audit-hero,.report-hero,.profile-hero{border-color:color-mix(in srgb,var(--role-accent) 28%,rgba(255,255,255,.75))}.report-list{display:grid;gap:10px}.report-row{display:flex;justify-content:space-between;align-items:center;gap:14px;padding:12px 14px;border:1px solid var(--line);border-radius:16px;background:rgba(255,255,255,.72)}.report-row strong{font-size:22px;color:var(--role-accent)}.wishlist-list{display:grid;gap:10px}.wishlist-item{display:flex;justify-content:space-between;align-items:center;gap:12px;padding:12px 14px;border:1px solid var(--line);border-radius:18px;background:linear-gradient(135deg,#fff,rgba(255,247,223,.72))}.wish-badge{display:inline-flex;vertical-align:middle;margin-left:6px;padding:3px 8px;border-radius:999px;background:#fff7df;color:#9a6500;font-size:12px;font-weight:900}.reward-card .row:last-child{margin-top:2px}.theme-preview{display:grid;grid-template-columns:repeat(3,1fr);gap:10px;margin-top:14px}.theme-preview div{min-height:54px;border-radius:16px;border:1px solid var(--line)}.theme-preview div:nth-child(1){background:linear-gradient(135deg,#fff,#eef3ff)}.theme-preview div:nth-child(2){background:linear-gradient(135deg,#101827,#26334d)}.theme-preview div:nth-child(3){background:linear-gradient(135deg,var(--hero1),var(--hero2))}.profile-badges{grid-template-columns:repeat(2,minmax(0,1fr))}
.practice-list{display:grid;gap:12px;margin-top:14px}.practice-list>div{padding:12px 14px;border:1px solid var(--line);border-radius:16px;background:rgba(255,255,255,.68)}.practice-list p{margin:6px 0 0;color:var(--muted)}.practice-grid{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:12px}.practice-grid.compact{grid-template-columns:repeat(2,minmax(0,1fr))}.practice-card{display:grid;gap:6px;justify-items:start;text-align:left;padding:14px;border:1px solid var(--line);border-radius:18px;background:linear-gradient(135deg,#fff,rgba(255,255,255,.72));color:var(--text);box-shadow:none}.practice-card.static{cursor:default}.practice-card span{font-size:24px}.practice-card b{font-size:14px}.practice-card small{color:var(--muted);line-height:1.35}.preset-block{margin-top:18px;padding-top:16px;border-top:1px solid var(--line)}.preset-block h3{margin:0 0 6px}.speech-grid{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:12px}.speech-card{padding:14px;border:1px solid var(--line);border-radius:18px;background:rgba(255,255,255,.72)}.speech-card span{display:inline-flex;margin-bottom:8px;padding:4px 9px;border-radius:999px;background:var(--soft);color:var(--role-accent);font-size:12px;font-weight:900}.speech-card p{margin:0;color:var(--muted);line-height:1.55}.principle-list{display:grid;gap:8px;padding-left:22px}.principle-list li{line-height:1.6}
button{transition:transform .16s ease,box-shadow .16s ease,opacity .16s ease}button:hover:not(:disabled){transform:translateY(-1px);box-shadow:0 12px 22px rgba(79,124,255,.20)}button.secondary:hover:not(:disabled),button.tab:hover:not(:disabled){box-shadow:0 8px 18px rgba(43,55,95,.08)}.toast{animation:toastIn .22s ease-out}@keyframes toastIn{from{opacity:0;transform:translateY(8px) scale(.98)}to{opacity:1;transform:translateY(0) scale(1)}}
@media(max-width:900px){.mini-stat-grid,.reward-shelf,.reward-shelf.compact,.practice-grid,.practice-grid.compact,.speech-grid{grid-template-columns:1fr}.overview-hero-card,.task-card,.wishlist-item{align-items:flex-start;flex-direction:column}.score-compass{grid-template-columns:1fr}.hero-panel{justify-items:start;width:100%}.realtime-clock{grid-template-columns:1fr;min-width:0;width:100%;justify-self:stretch}.clock-analog-panel{justify-content:space-between}.clock-date{text-align:left}.task-side{justify-content:flex-start}.report-row{align-items:flex-start;flex-direction:column}.report-row strong{font-size:26px}}
@media(prefers-reduced-motion:reduce){*{animation:none!important;transition:none!important;scroll-behavior:auto!important}}

:root{
  --bg:#f6f7fb;
  --card:#ffffff;
  --text:#182033;
  --muted:#697386;
  --primary:#4f7cff;
  --primary2:#7c5cff;
  --good:#19a974;
  --warn:#f5a623;
  --bad:#e05260;
  --line:#e7eaf1;
  --hero1:#eef3ff;
  --hero2:#fff7ed;
  --soft:#eef2ff;
  --role-accent:#4f7cff;
}
*{box-sizing:border-box}
body{
  min-height:100vh;
  margin:0;
  font-family:-apple-system,BlinkMacSystemFont,"Segoe UI","PingFang SC","Microsoft YaHei",sans-serif;
  background:linear-gradient(135deg,var(--hero1) 0%,var(--hero2) 100%);
  color:var(--text);
  transition:background .35s ease,color .2s ease;
}
body::before{
  content:"";
  position:fixed;
  inset:0;
  z-index:-1;
  pointer-events:none;
  background:
    radial-gradient(circle at 12% 12%,rgba(255,255,255,.85),transparent 28%),
    radial-gradient(circle at 86% 18%,rgba(255,255,255,.58),transparent 24%),
    radial-gradient(circle at 50% 92%,rgba(255,255,255,.5),transparent 34%);
}
body[data-role="admin"]{--hero1:#e9edff;--hero2:#f5ecff;--soft:#eef2ff;--role-accent:#7c3aed}
body[data-role="parent"]{--hero1:#e8fff4;--hero2:#fff7dc;--soft:#e7fff4;--role-accent:#169b72}
body[data-role="child"]{--hero1:#fff1c7;--hero2:#e6f8ff;--soft:#fff4de;--role-accent:#ff8a3d}
body[data-role="guest"]{--hero1:#eef3ff;--hero2:#fff7ed;--soft:#eef2ff;--role-accent:#4f7cff}
body[data-theme="dark"]{--bg:#0f172a;--card:#172033;--text:#e5edf9;--muted:#9fb0c8;--line:#29364d;--hero1:#101827;--hero2:#1a2438;--soft:#26334d;color-scheme:dark}
body[data-theme="dark"]::before{background:radial-gradient(circle at 12% 12%,rgba(79,124,255,.16),transparent 28%),radial-gradient(circle at 86% 18%,rgba(124,92,255,.14),transparent 24%),radial-gradient(circle at 50% 92%,rgba(25,169,116,.10),transparent 34%)}
body[data-theme="dark"] .card,body[data-theme="dark"] .hero{background:linear-gradient(135deg,rgba(23,32,51,.94),rgba(23,32,51,.72));border-color:rgba(148,163,184,.18)}
body[data-theme="dark"] .tab,body[data-theme="dark"] button.secondary,body[data-theme="dark"] .profile-entry,body[data-theme="dark"] .realtime-clock,body[data-theme="dark"] .field input,body[data-theme="dark"] .field select,body[data-theme="dark"] .field textarea,body[data-theme="dark"] .timeline-item,body[data-theme="dark"] .task-card,body[data-theme="dark"] .reward-card,body[data-theme="dark"] .report-row,body[data-theme="dark"] .speech-card,body[data-theme="dark"] .practice-card,body[data-theme="dark"] .practice-list>div,body[data-theme="dark"] .wishlist-item{background:#172033;color:var(--text);border-color:var(--line)}
body[data-theme="dark"] .analog-clock{background:radial-gradient(circle at center,#172033 0%,#172033 58%,#26334d 59%,#26334d 100%)}body[data-theme="dark"] .clock-pin{box-shadow:0 0 0 3px #172033}
body[data-theme="dark"] .notice{background:#2b230f;color:#ffd98a;border-color:#5b4212}body[data-theme="dark"] .progress-ring-inner{background:#111827}body[data-theme="dark"] .empty-state{background:rgba(23,32,51,.6)}body[data-theme="dark"] .tag{background:#26334d;color:#dbeafe}
button,input,select,textarea{font:inherit}
button{border:0;border-radius:12px;padding:10px 14px;background:linear-gradient(135deg,var(--primary),var(--primary2));color:#fff;cursor:pointer;font-weight:700;box-shadow:0 8px 18px rgba(79,124,255,.18)}
button.secondary{background:#eef2ff;color:#334155;box-shadow:none}
button.danger{background:var(--bad)}
button:disabled{opacity:.55;cursor:not-allowed}
.layout{max-width:1180px;margin:0 auto;padding:24px}
.hero{display:flex;justify-content:space-between;gap:16px;align-items:center;margin-bottom:20px;padding:20px;border:1px solid rgba(255,255,255,.75);border-radius:28px;background:linear-gradient(135deg,rgba(255,255,255,.84),rgba(255,255,255,.58));box-shadow:0 18px 50px rgba(43,55,95,.10);backdrop-filter:blur(14px)}
